```typescript
// formatCurrency.ts
export function formatCurrency(cents: number, currency: string): string {
  // Validate currency code
  const supportedCurrencies = ['USD', 'EUR', 'GBP', 'JPY', 'CAD', 'AUD'];
  if (!supportedCurrencies.includes(currency)) {
    throw new Error(`Unsupported currency code: ${currency}`);
  }

  // Handle negative values
  const isNegative = cents < 0;
  const absoluteCents = Math.abs(cents);

  // Convert cents to currency units
  const dollars = absoluteCents / 100;

  // Format with proper locale and currency
  const formatter = new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: currency,
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  });

  const formatted = formatter.format(dollars);

  // Add negative sign if needed
  return isNegative ? `-${formatted}` : formatted;
}
