// formatCurrency.test.ts
import { formatCurrency } from './formatCurrency';

describe('formatCurrency', () => {
  describe('basic formatting', () => {
    test('should format standard values correctly', () => {
      expect(formatCurrency(1999, 'USD')).toBe('$19.99');
    });

    test('should format zero correctly', () => {
      expect(formatCurrency(0, 'USD')).toBe('$0.00');
    });

    test('should handle values less than 100 cents', () => {
      expect(formatCurrency(99, 'USD')).toBe('$0.99');
    });

    test('should handle single digit cents', () => {
      expect(formatCurrency(5, 'USD')).toBe('$0.05');
    });
  });

  describe('negative values', () => {
    test('should format negative values with minus sign', () => {
      expect(formatCurrency(-1999, 'USD')).toBe('-$19.99');
    });

    test('should format negative zero correctly', () => {
      expect(formatCurrency(-0, 'USD')).toBe('$0.00');
    });

    test('should format small negative values', () => {
      expect(formatCurrency(-50, 'USD')).toBe('-$0.50');
    });
  });

  describe('large values', () => {
    test('should format values over 1 billion cents', () => {
      const billionCents = 100_000_000_000; // $1 billion
      expect(formatCurrency(billionCents, 'USD')).toBe('$1,000,000,000.00');
    });

    test('should format values over 1 trillion cents', () => {
      const trillionCents = 100_000_000_000_000; // $1 trillion
      expect(formatCurrency(trillionCents, 'USD')).toBe('$1,000,000,000,000.00');
    });

    test('should format large values with decimal precision', () => {
      expect(formatCurrency(123_456_789, 'USD')).toBe('$1,234,567.89');
    });
  });

  describe('floating-point precision', () => {
    test('should maintain precision with 1999 cents', () => {
      const result = formatCurrency(1999, 'USD');
      expect(result).toBe('$19.99');
      expect(result).not.toMatch(/19\.990|19\.989/); // No precision errors
    });

    test('should handle cents that would cause floating-point errors', () => {
      expect(formatCurrency(0.1 * 1000, 'USD')).toBe('$10.00');
    });

    test('should correctly round edge case values', () => {
      // 19.995 cents should round to $0.20, not $0.19
      expect(formatCurrency(20, 'USD')).toBe('$0.20');
    });
  });

  describe('currency support', () => {
    test('should format USD correctly', () => {
      expect(formatCurrency(5000, 'USD')).toBe('$50.00');
    });

    test('should format EUR correctly', () => {
      expect(formatCurrency(5000, 'EUR')).toBe('€50.00');
    });

    test('should format GBP correctly', () => {
      expect(formatCurrency(5000, 'GBP')).toBe('£50.00');
    });

    test('should format CAD correctly', () => {
      expect(formatCurrency(5000, 'CAD')).toBe('CA$50.00');
    });

    test('should format AUD correctly', () => {
      expect(formatCurrency(5000, 'AUD')).toBe('A$50.00');
    });

    test('should format JPY correctly', () => {
      expect(formatCurrency(5000, 'JPY')).toBe('¥50.00');
    });
  });

  describe('error handling', () => {
    test('should throw error for unsupported currency code', () => {
      expect(() => formatCurrency(1000, 'XYZ')).toThrow(
        'Unsupported currency code: XYZ'
      );
    });

    test('should throw error for lowercase currency code', () => {
      expect(() => formatCurrency(1000, 'usd')).toThrow(
        'Unsupported currency code: usd'
      );
    });

    test('should throw error for invalid currency code (numbers)', () => {
      expect(() => formatCurrency(1000, '123')).toThrow(
        'Unsupported currency code: 123'
      );
    });

    test('should throw error for empty string currency', () => {
      expect(() => formatCurrency(1000, '')).toThrow(
        'Unsupported currency code: '
      );
    });
  });

  describe('edge cases', () => {
    test('should handle maximum safe integer', () => {
      expect(formatCurrency(Number.MAX_SAFE_INTEGER, 'USD')).toMatch(/\$/);
    });

    test('should format round dollar amounts', () => {
      expect(formatCurrency(10000, 'USD')).toBe('$100.00');
    });

    test('should format odd cent amounts', () => {
      expect(formatCurrency(1, 'USD')).toBe('$0.01');
    });

    test('should maintain leading zeros in cents', () => {
      const result = formatCurrency(1050, 'USD');
      expect(result).toBe('$10.50');
      expect(result).toMatch(/\.50$/);
    });
  });

  describe('consistency', () => {
    test('should produce consistent results for same input', () => {
      const result1 = formatCurrency(1999, 'USD');
      const result2 = formatCurrency(1999, 'USD');
      expect(result1).toBe(result2);
    });

    test('should produce consistent results across multiple currencies', () => {
      const cents = 5000;
      const usdResult = formatCurrency(cents, 'USD');
      const eurResult = formatCurrency(cents, 'EUR');

      expect(usdResult).toMatch(/50\.00/);
      expect(eurResult).toMatch(/50\.00/);
    });
  });
});
